var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>같은 시간</color>","JPN":"<color=#ffd34c>そのころ</color>","ENG":"<color=#ffd34c>Meanwhile</color>","TWN":"<color=#ffd34c>同一時間</color>","SCN":"<color=#ffd34c>同一时间</color>","DEU":"<color=#ffd34c>Meanwhile</color>","FRA":"<color=#ffd34c>Meanwhile</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제9본부, 집무실","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第9本部、執務室","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ, Office","TWN":"<color=#ffd34c>聖皇廳</color> 奇蹟議會第9總部,辦公室","SCN":"<color=#ffd34c>圣廷</color> 奇迹议会第9本部, 办公室","DEU":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ, Office","FRA":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ, Office"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아무리 인수인계가 늦어졌다고는 하지만…….","JPN":"いくら業務の引継ぎが遅れたとはいえ……","ENG":"I know the handover took longer than expected, but...","TWN":"雖然交接工作有所延遲……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"설마, 올해까지 결재가 필요한 성무 보고서가 이렇게나 쌓여 있을 줄이야…….","JPN":"まさか、今年までに決裁しないといけない聖務報告書がこんなに山積みになっていたとは……","ENG":"I never would have thought that there would be so many reports needing to be approved by the end of this year...","TWN":"沒想到，今年需要審批的聖務報告竟然堆積如山……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"쉬는 날이라고 순순히 쉴 수 있을 거로 생각하진 않았지만… 이건 좀 심하군.","JPN":"休みだからといって本当に休めるとは思っていなかったけど……これは少しひどいわね。","ENG":"I was expecting to work on holidays and weekends, but... this seems a bit too much.","TWN":"雖然沒指望休息日真的能休息……但這也太過分了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"게다가 예하께서 남기신 이 함선 렌탈 계약서들…….","JPN":"それに、猊下が残したこの艦船レンタル契約書……","ENG":"All these ship rental contracts that His Eminence left behind...","TWN":"而且這些是主教留下的艦船租賃契約書……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자그마치 15년 치 분량이야. 기재 사항은 전부 엉터리에다가 대여 목적이 낚시라고……?","JPN":"なんと15年分よ。記載事項は全部デタラメで、レンタルの目的が釣り……？","ENG":"There is nearly fifteen years’ worth of them. All the information written down is wrong, and the reason for renting was fishing...?","TWN":"足足有15年的分量，記錄事項全是胡編亂造，借用目的竟然是釣魚……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대체 예하께서는 왜 이런 문서를 금고에 보관하고 계셨던 거지?","JPN":"いったいどうして猊下はこんな文書を金庫で保管されてたんだろう？","ENG":"Why on earth did His Eminence keep these documents in his safe?","TWN":"到底為什麼會把這種檔保存在保險櫃裡？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"내가 모르는 동안 예하께선 무슨 일을…….","JPN":"私の知らない間に、猊下はいったい何を……","ENG":"What was he doing while I was not here...?","TWN":"到底瞞著我做了些什麼……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"후우… 아직은 맥락을 읽을 수 없어.","JPN":"ふう……まだ脈絡がわからないわ。","ENG":"*Sigh* I cannot read the context yet.","TWN":"呼… 到現在還是無法理解。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"정보가 부족해. 알아내려면 조금 시간이 필요할지도 모르겠네.","JPN":"情報が足りない。突き止めるには少し時間が必要かも。","ENG":"I need more information. This might take some time to find out.","TWN":"資訊不足，要弄清楚可能需要一些時間。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"벌써 시간이… 슬슬 시스터 루퍼의 심사가 끝날 때인가.","JPN":"もう時間が……そろそろシスター・ルーパーの審査が終わる頃か。","ENG":"Look at the time... Sister Looper's evaluation should be over soon.","TWN":"已經這麼晚了……是不是快到洛珀姊妹的考核結束的時候了？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결과가 어떻게 났을지는 모르겠지만, 그래도 마중은 나가는 편이 좋겠지.","JPN":"どんな結果になったかはわからないけど、迎えに行った方がいいわよね。","ENG":"I do not know what her results will be, but I still should go get her.","TWN":"結果如何我不知道，但還是去接一下比較好吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잠시 한눈을 팔았다간, 또 그 꼬맹이 시스터가 무슨 사고를 칠지 모르니까 말이야.","JPN":"少しでも目を離すと、あのチビシスターが何をやらかすかわからないし。","ENG":"Who knows what kind of trouble she will cause while no one is watching her.","TWN":"稍微一分心，那小丫頭修女又不知道會闖什麼禍。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 또 시스터 넬슨은 여기저기 사과를 하고 다니겠고…….","JPN":"そうなると、シスター・ネルソンはまたあちこち謝って回って……","ENG":"Then, Sister Nelson will have to go around apologizing for her actions, and–","TWN":"然後，尼爾森姊妹又要到處道歉了……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"으음?","JPN":"ううん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러고 보니, 시스터 넬슨은 성탄제를 준비한다고 했었나?","JPN":"そういえば、シスター・ネルソンは聖誕祭の準備をするって言っていたわよね。","ENG":"Come to think of it, Sister Nelson mentioned preparing a Christmas party.","TWN":"話說，尼爾森姊妹不是說她在準備聖誕節嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제5본당이라면, 여기서 그렇게 멀지는 않군.","JPN":"第5本堂なら、ここからそう遠くないか。","ENG":"The 5th Parish should be close to here.","TWN":"如果是第5主堂的話，離這裡不遠。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제멋대로인 시스터 루퍼에 비해서야 훨씬 낫지만, 시스터 넬슨도 의욕이 과한 편이지.","JPN":"自分勝手なシスター・ルーパーに比べるとずっとましだけど、シスター・ネルソンも熱意が過剰なのよね。","ENG":"Sister Nelson might be better than the self-indulged Sister Looper, but she's also overly ambitious.","TWN":"雖然比起任性的洛珀要好得多，但尼爾森姊妹也有些過於積極了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사실은 루퍼 자매님에게 특별한 추억을 만들어 주고 싶거든요.","JPN":"実はシスター・シンディに特別な思い出を作ってあげたいのです。","ENG":"In truth, I wanted to create a special memory for Sister Looper.","TWN":"其實是想給洛珀姊妹留下特別的回憶。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"추억이라고요?","JPN":"思い出ですか？","ENG":"A special memory?","TWN":"回憶嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 왜냐하면 루퍼 자매님은 한 번도 제대로 된 성탄절을 맞이한 적이 없을 테니까요.","JPN":"はい。だって、シスター・シンディは一度もちゃんとした聖誕祭を迎えたことがないでしょうから。","ENG":"Yes. Because she has never properly celebrated Christmas before.","TWN":"是的，因為洛珀姊妹從來沒有過一個真正的聖誕節。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};